+	switch runtime.GOOS {
+	case "darwin":
+		ides := map[string]string{
+			"/Applications/IntelliJ IDEA.app":          "IntelliJ IDEA",
+			"/Applications/IntelliJ IDEA CE.app":       "IntelliJ IDEA CE",
+			"/Applications/GoLand.app":                 "GoLand",
+			"/Applications/PyCharm.app":                "PyCharm",
